<?php
require_once __DIR__ . '/config.php'; require_login(); require_once __DIR__ . '/app_ui.php';
if (!is_admin()) { header('Location: calendar.php'); exit; }
function us_h($v): string { return htmlspecialchars((string)$v, ENT_QUOTES, 'UTF-8'); }
function us_ensure_schema(PDO $pdo): void { $pdo->exec("CREATE TABLE IF NOT EXISTS users (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(160) NULL,email VARCHAR(160) NOT NULL,password VARCHAR(255) NOT NULL,role VARCHAR(40) NOT NULL DEFAULT 'admin',active TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci"); foreach(['name'=>'VARCHAR(160) NULL','email'=>'VARCHAR(160) NULL','password'=>'VARCHAR(255) NULL','role'=>"VARCHAR(40) NOT NULL DEFAULT 'admin'",'active'=>'TINYINT(1) NOT NULL DEFAULT 1','created_at'=>'TIMESTAMP DEFAULT CURRENT_TIMESTAMP'] as $c=>$d){$st=$pdo->prepare("SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='users' AND COLUMN_NAME=?");$st->execute([$c]);if((int)$st->fetchColumn()===0)$pdo->exec("ALTER TABLE users ADD COLUMN {$c} {$d}");}}
us_ensure_schema($pdo); $error=''; $success=''; $currentUserId=function_exists('current_user_id')?(int)(current_user_id()??0):0;
if($_SERVER['REQUEST_METHOD']==='POST'){ csrf_require(); $action=$_POST['action']??''; if($action==='create_user'||$action==='update_user'){ $id=(int)($_POST['user_id']??0); $name=trim((string)($_POST['name']??'')); $email=trim((string)($_POST['email']??'')); $password=(string)($_POST['password']??''); $active=!empty($_POST['active'])?1:0; if($name===''||$email==='')$error='Completează numele si emailul.'; elseif(!filter_var($email,FILTER_VALIDATE_EMAIL))$error='Emailul nu este valid.'; elseif($action==='create_user'&&trim($password)==='')$error='Completează parola.'; elseif($action==='update_user'&&$id===$currentUserId&&$active===0)$error='Nu iti poți dezactiva propriul cont.'; else { try { if($action==='create_user'){ $st=$pdo->prepare("SELECT COUNT(*) FROM users WHERE email=?");$st->execute([$email]); if((int)$st->fetchColumn()>0)$error='Există deja un utilizator cu acest email.'; else {$st=$pdo->prepare("INSERT INTO users (name,email,password,role,active) VALUES (?,?,?,'admin',?)");$st->execute([$name,$email,password_hash($password,PASSWORD_DEFAULT),$active]);$success='Utilizatorul a fost adaugat.';} } else { $st=$pdo->prepare("SELECT COUNT(*) FROM users WHERE email=? AND id<>?");$st->execute([$email,$id]); if((int)$st->fetchColumn()>0)$error='Există deja alt utilizator cu acest email.'; else { if(trim($password)!==''){ $st=$pdo->prepare("UPDATE users SET name=?,email=?,password=?,active=? WHERE id=?");$st->execute([$name,$email,password_hash($password,PASSWORD_DEFAULT),$active,$id]); } else { $st=$pdo->prepare("UPDATE users SET name=?,email=?,active=? WHERE id=?");$st->execute([$name,$email,$active,$id]); } $success='Utilizatorul a fost actualizat.'; } } } catch(Throwable $e){error_log('PestZone users save: '.$e->getMessage());$error='Utilizatorul nu a putut fi salvat.';} } } if($action==='delete_user'){ $id=(int)($_POST['user_id']??0); if($id===$currentUserId)$error='Nu iti poți sterge propriul cont.'; elseif($id>0){ try{$pdo->prepare("DELETE FROM users WHERE id=?")->execute([$id]);$success='Utilizatorul a fost șters.';}catch(Throwable $e){$error='Utilizatorul nu a putut fi șters.';}} }}
$users=$pdo->query("SELECT id,name,email,role,active,created_at FROM users ORDER BY active DESC,name ASC,email ASC")->fetchAll(PDO::FETCH_ASSOC);
?>
<!DOCTYPE html><html lang="ro"><head><meta charset="UTF-8"><title>Utilizatori - PestZone</title><meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, viewport-fit=cover"><link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Inter:ital,opsz,wght@0,14..32,400;0,14..32,500;0,14..32,600;0,14..32,700;1,14..32,400&display=swap" rel="stylesheet"><?php app_theme_css(); ?><style>* { font-family:'Inter',system-ui,sans-serif !important; }
.top{padding:12px 20px}.wrap{max-width:1160px;margin:0 auto;display:flex;flex-direction:column;gap:16px}
