input{width:100%;border:1px solid var(--pz-line);border-radius:var(--pz-rs);min-height:34px;padding:7px 10px;font-weight:500}
input:focus{border-color:var(--pz-bl);outline:none}
.check{display:flex;gap:8px;align-items:center;font-weight:500}
.check input{width:16px;height:16px;min-height:auto;accent-color:var(--pz-bl)}
.actions,.row-actions{display:flex;gap:8px;flex-wrap:wrap}
.mini{border:1px solid var(--pz-line);background:var(--pz-surf);border-radius:var(--pz-rs);padding:5px 9px;font-weight:600;font-size:12px;cursor:pointer}
.mini:hover{border-color:var(--pz-blb);color:var(--pz-bl);background:var(--pz-bls)}
