.notice.ok{background:var(--pz-grs);color:var(--pz-gr);border:1px solid var(--pz-grb)}
.notice.err{background:var(--pz-res);color:var(--pz-re);border:1px solid var(--pz-reb)}
@media(max-width:960px){.grid{grid-template-columns:1fr}}</style></head><body><div class="layout"><?php render_sidebar('settings',true); ?><main class="main"><div class="content wrap"><?php pz_page_header(['back' => ['href' => 'settings.php', 'label' => 'Înapoi la setări'], 'kicker' => 'Setări', 'title' => 'Utilizatori', 'subtitle' => 'Utilizatorii de birou au acces administrativ. Tehnicienii se gestionează din modulul Tehnicieni.']); ?><?php if($success):?><div class="notice ok"><?=us_h($success)?></div><?php endif;?><?php if($error):?><div class="notice err"><?=us_h($error)?></div><?php endif;?><div class="grid"><section class="card"><h2 style="margin:0 0 14px">Lista utilizatori</h2><div class="table-wrap"><table><thead><tr><th>Nume</th><th>Email</th><th>Status</th><th>Creat</th><th>Acțiuni</th></tr></thead><tbody><?php foreach($users as $u): ?><tr><td><?=us_h($u['name']?:'Fara nume')?><?php if((int)$u['id']===$currentUserId):?><div class="muted">contul tau</div><?php endif;?></td><td><?=us_h($u['email'])?></td><td><?=((int)$u['active']?'<span class="badge ok">Activ</span>':'<span class="badge off">Inactiv</span>')?></td><td><span class="muted"><?=us_h($u['created_at']??'')?></span></td><td><div class="row-actions"><button class="mini" type="button" onclick='editUser(<?=json_encode(['id'=>(int)$u['id'],'name'=>(string)($u['name']??''),'email'=>(string)$u['email'],'active'=>(int)$u['active']],JSON_HEX_TAG|JSON_HEX_APOS|JSON_HEX_AMP|JSON_HEX_QUOT)?>)'>Editează</button><?php if((int)$u['id']!==$currentUserId):?><form method="post" onsubmit="return confirm('Stergi acest utilizator?')"><?=csrf_field()?><input type="hidden" name="action" value="delete_user"><input type="hidden" name="user_id" value="<?=(int)$u['id']?>"><button class="mini danger" type="submit">Șterge</button></form><?php endif;?></div></td></tr><?php endforeach; ?></tbody></table></div></section><aside class="card"><h2 id="formTitle" style="margin:0 0 14px">Adaugă utilizator</h2><form method="post" class="form-grid" id="userForm"><?=csrf_field()?><input type="hidden" name="action" id="action" value="create_user"><input type="hidden" name="user_id" id="user_id" value="0"><label>Nume<input name="name" id="name" required></label><label>Email<input type="email" name="email" id="email" required></label><label>Parola<input type="password" name="password" id="password" autocomplete="new-password"><span class="muted">La editare, lasa gol dacă nu schimbi parola.</span></label><label class="check"><input type="checkbox" name="active" id="active" value="1" checked> Utilizator activ</label><div class="actions"><button class="btn accent" type="submit">Salvează</button><button class="btn ghost" type="button" onclick="resetUserForm()">Curata</button></div></form></aside></div></div></main></div><script>function editUser(u){formTitle.textContent='Editează utilizator';action.value='update_user';user_id.value=u.id||0;name.value=u.name||'';email.value=u.email||'';password.value='';active.checked=String(u.active)==='1';name.focus();}function resetUserForm(){userForm.reset();formTitle.textContent='Adaugă utilizator';action.value='create_user';user_id.value='0';active.checked=true;}</script></body></html>
